1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = { type: string };
13	type QuoteStep = { op: "quote"; items: Item[] };
14	type Step = QuoteStep;
15	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
16	type QuoteResult = { premium: number };
17	type ScenarioResult = { results: QuoteResult[] };
18	
19	const COMPONENT_BLOCK_SIZE = 3;
20	const COMPONENT_BLOCK_PREMIUM = 60;
21	
22	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type];
23	
24	const policyBasePremium = (items: Item[]): number => {
25	  if (
26	    items.length === COMPONENT_BLOCK_SIZE &&
27	    items.every((item) => item.type === "rune")
28	  ) {
29	    return COMPONENT_BLOCK_PREMIUM;
30	  }
31	  return items.reduce((sum, item) => sum + itemBasePremium(item), 0);
32	};
33	
34	const quotePremium = (items: Item[]): number => {
35	  const basePremium = policyBasePremium(items);
36	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
37	  return basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
38	};
39	
40	export const runScenario = (scenario: Scenario): ScenarioResult => {
41	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
42	  return { results };
43	};
